@startuml
title <u><b>CATEGORY's Class Diagram</b></u>

skinparam shadowing false
skinparam packageStyle rectangle
skinparam packageBorderThickness 2
skinparam classBorderThickness 1
skinparam classBackgroundColor #F2F2F2
skinparam classAttributeIconSize 0

package "jp" {
  package "ac" {
    package "shibaura" {
      package "it" {
        package "ie" {

          package "domain" {
            package "model" {
              package "category" {
                interface "CategoryRepository" as CategoryRepository
              }
            }
          }

          package "gateways" {
            package "category" {
              class "MySQLCategoryRepository" as MySQLCategoryRepository {
                +findAll()
                +save()
              }
            }
          }

          MySQLCategoryRepository ..|> CategoryRepository

        }
      }
    }
  }
}
@enduml
